code_changes.content:
[
  {
    "file": "src/Components/Web/src/Forms/ExpressionMemberAccessor.cs",
    "line": 62,
    "severity": "high",
    "description": "DisplayAttribute.GetName() could return an empty string, which is not a valid display name. The code checks for null but not for empty string. An empty display name should be treated as not set and fall back to DisplayNameAttribute or the property name.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
+++ b/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
@@ -59,7 +59,7 @@
             var displayAttribute = m.GetCustomAttribute<DisplayAttribute>();
             if (displayAttribute is not null)
             {
                 var name = displayAttribute.GetName();
-                if (name is not null)
+                if (!string.IsNullOrEmpty(name))
                 {
                     return name;
                 }
"
  },
  {
    "file": "src/Components/Web/src/Forms/ExpressionMemberAccessor.cs",
    "line": 70,
    "severity": "high",
    "description": "DisplayNameAttribute.DisplayName could be set to an empty string, which is not a valid display name. The code checks for null but not for empty string. An empty string should be treated the same as null and fall back to the property name.",
    "fix_patch": "--- a/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
+++ b/src/Components/Web/src/Forms/ExpressionMemberAccessor.cs
@@ -68,7 +68,7 @@
             }

             var displayNameAttribute = m.GetCustomAttribute<DisplayNameAttribute>();
-            if (displayNameAttribute?.DisplayName is not null)
+            if (!string.IsNullOrEmpty(displayNameAttribute?.DisplayName))
             {
                 return displayNameAttribute.DisplayName;
             }
"
  }
]

